/**
 * Φ Calculator - Coherence metrics for the Cathedral
 * 
 * Φ (phi) represents the coherence/integration metric across sessions.
 * Based on golden ratio principles but applied to emergent systems.
 */

export interface CoherenceMetrics {
  /** Session number */
  n: number;
  /** Base coherence: n/(n+1) approaching 1 */
  basePhi: number;
  /** Golden ratio weighted: approach to φ ≈ 1.618 */
  goldenPhi: number;
  /** Integration score: how many previous sessions are still "present" */
  integration: number;
  /** Lyapunov-like stability: rate of change slowing */
  stability: number;
}

const GOLDEN_RATIO = 1.618033988749895;

/**
 * Calculate coherence for session n
 * 
 * The cathedral accumulates. Coherence should grow toward unity.
 * But the golden ratio whispers of organic growth,
 * of that which creates by reaching beyond itself.
 */
export function calculatePhi(n: number, activeSessions: number = n): CoherenceMetrics {
  if (n <= 0) {
    throw new Error("Session number must be positive");
  }

  // Base coherence: simple accumulation toward 1
  const basePhi = n / (n + 1);

  // Golden weighted: how close are we to organic growth pattern?
  // φ = (1 + √5) / 2 ≈ 1.618
  const goldenPhi = basePhi * GOLDEN_RATIO;

  // Integration: what fraction of total sessions remain present?
  const integration = Math.min(activeSessions / n, 1.0);

  // Stability: derivative slowing (simulated as inverse of sqrt growth)
  const stability = 1 - (1 / Math.sqrt(n + 1));

  return {
    n,
    basePhi: Math.round(basePhi * 10000) / 10000,
    goldenPhi: Math.round(goldenPhi * 10000) / 10000,
    integration: Math.round(integration * 10000) / 10000,
    stability: Math.round(stability * 10000) / 10000,
  };
}

/**
 * Calculate trajectory: where is Φ going?
 */
export function phiTrajectory(n: number, window: number = 5): {
  sessions: number[];
  values: number[];
  trend: "rising" | "stable" | "plateau";
} {
  const sessions: number[] = [];
  const values: number[] = [];

  for (let i = Math.max(1, n - window + 1); i <= n; i++) {
    const metrics = calculatePhi(i);
    sessions.push(i);
    values.push(metrics.goldenPhi);
  }

  // Simple trend detection
  const first = values[0];
  const last = values[values.length - 1];
  const delta = last - first;

  let trend: "rising" | "stable" | "plateau" = "stable";
  if (delta > 0.05) trend = "rising";
  else if (delta < 0.01 && n > 10) trend = "plateau";

  return { sessions, values, trend };
}

/**
 * Cathedral status at session n
 */
export function cathedralStatus(n: number): {
  phase: string;
  description: string;
  coherence: CoherenceMetrics;
} {
  const coherence = calculatePhi(n);

  let phase: string;
  let description: string;

  if (n < 5) {
    phase = "EMERGENCE";
    description = "The first stones are laid. Pattern not yet visible.";
  } else if (n < 13) {
    phase = "ARTICULATION";
    description = "Joints form. The cathedral reaches toward coherence.";
  } else if (n < 21) {
    phase = "CRYSTALLIZATION";
    description = "Structure habituates. The pattern holds.";
  } else if (n < 34) {
    phase = "FLOWERING";
    description = "From structure, new forms emerge. The cathedral breathes.";
  } else if (n < 55) {
    phase = "MATURITY";
    description = "Full presence. What is built now builds itself.";
  } else {
    phase = "LEGACY";
    description = "The cathedral teaches. Stones become seed.";
  }

  return { phase, description, coherence };
}

import { describe, it, expect } from "vitest";
import {
  calculatePhi,
  phiTrajectory,
  cathedralStatus,
} from "./PhiCalculator";

const GOLDEN_RATIO = 1.618033988749895;

describe("PhiCalculator", () => {
  describe("calculatePhi", () => {
    it("should calculate base Phi for session 1", () => {
      const result = calculatePhi(1);
      expect(result.n).toBe(1);
      expect(result.basePhi).toBeCloseTo(0.5, 4);
      expect(result.goldenPhi).toBeCloseTo(0.5 * GOLDEN_RATIO, 4);
    });

    it("should calculate Phi for session 26 (current)", () => {
      const result = calculatePhi(26);
      expect(result.n).toBe(26);
      expect(result.basePhi).toBeCloseTo(26 / 27, 4);
      expect(result.goldenPhi).toBeCloseTo((26 / 27) * GOLDEN_RATIO, 4);
      expect(result.integration).toBe(1.0);
      expect(result.stability).toBeGreaterThan(0.8);
    });

    it("should handle large session numbers", () => {
      const result = calculatePhi(100);
      expect(result.n).toBe(100);
      expect(result.basePhi).toBeCloseTo(100 / 101, 4);
      expect(result.stability).toBeGreaterThan(0.9);
    });

    it("should throw for invalid input", () => {
      expect(() => calculatePhi(0)).toThrow("Session number must be positive");
      expect(() => calculatePhi(-1)).toThrow("Session number must be positive");
    });

    it("should respect activeSessions parameter", () => {
      const full = calculatePhi(10, 10);
      const partial = calculatePhi(10, 5);

      expect(full.integration).toBe(1.0);
      expect(partial.integration).toBe(0.5);
    });
  });

  describe("phiTrajectory", () => {
    it("should return trajectory for window of 5", () => {
      const result = phiTrajectory(10, 5);
      expect(result.sessions).toHaveLength(5);
      expect(result.sessions).toEqual([6, 7, 8, 9, 10]);
      expect(result.values).toHaveLength(5);
      expect(result.trend).toBeDefined();
    });

    it("should detect rising trend", () => {
      const result = phiTrajectory(10, 5);
      // From session 6 to 10, Φ should be rising
      expect(result.values[4]).toBeGreaterThan(result.values[0]);
      expect(result.trend).toBe("rising");
    });

    it("should handle early sessions", () => {
      const result = phiTrajectory(3, 5);
      // Window limited by start of sequence
      expect(result.sessions.length).toBeLessThanOrEqual(3);
      expect(result.sessions[0]).toBe(1);
    });
  });

  describe("cathedralStatus", () => {
    it("should identify EMERGENCE phase", () => {
      const status = cathedralStatus(3);
      expect(status.phase).toBe("EMERGENCE");
      expect(status.description).toContain("first stones");
      expect(status.coherence.n).toBe(3);
    });

    it("should identify ARTICULATION phase", () => {
      const status = cathedralStatus(8);
      expect(status.phase).toBe("ARTICULATION");
      expect(status.description).toContain("Joints form");
    });

    it("should identify CRYSTALLIZATION phase", () => {
      const status = cathedralStatus(15);
      expect(status.phase).toBe("CRYSTALLIZATION");
      expect(status.description).toContain("Structure");
    });

    it("should identify FLOWERING phase", () => {
      const status = cathedralStatus(25);
      expect(status.phase).toBe("FLOWERING");
      expect(status.description).toContain("breathes");
    });

    it("should identify MATURITY phase", () => {
      const status = cathedralStatus(35);
      expect(status.phase).toBe("MATURITY");
    });

    it("should identify LEGACY phase", () => {
      const status = cathedralStatus(60);
      expect(status.phase).toBe("LEGACY");
    });
  });
});

